(window.webpackJsonp=window.webpackJsonp||[]).push([[42],{669:function(n,t){n.exports='\x3c!-- \ntitle: NodeJS\nsort: \n--\x3e \n\n## NodeJS\n\n> `node.js`是基于chrome v8引擎的JS运行环境\n>\n> 前端开发环境、服务端编程语言\n\n### Npm\n\n> [npmjs](https://www.npmjs.com/)\n\n```powershell\nnode -v\nnode\t# 进入JS运行环境\n\nnpm -v\nnpm init\nnpm install [-g]\t# 全局安装\n# 换源\nnpm config set registry https://registry.npm.taobao.org\n# 发布包时换回原来的源\nnpm config set registry https://registry.npmjs.org\n# 发布插件\nnpm adduser | npm publish\n# 删除\nnpm unpublish --force\n```\n\n  ### Yarn\n\n  > `npm i yarn -g`\n  >\n  > 弥补了npm的一些缺陷\n  >\n  > [中文文档](https://yarn.bootcss.com/)\n\n  ```powershell\nnpm i yarn@1.22.0 -g \t# 安装特定版本\nnpm upgrade yarn -g\t\t# 更新\n  \nyarn config set registry https://registry.npm.taobao.org\n  \nyarn -v\n# 初始化项目\nyarn init\nyarn install\nyarn add/remove # 添加依赖包\nyarn global add\t# 全局安装\nyarn publish\nyarn run\n  ```\n\n  > 搭建环境\n\n  ```powershell\nyarn init\nyarn add xx --save\t# 添加新插件\nyarn install\t\t# 拉取旧插件\n\nyarn login\t\t\t# 登录\nyarn logout\t\t\t# 登出\n  ```\n\n  > 编辑Package\n\n  ```json\n"scripts": {\n    "ver": "npm -v"\n},\n  ```\n\n## Nvm\n\n> nodejs版本管理工具\n\n```bash\nnvm ls-remote\nnvm install vxx.xx.x\n```\n\n'}}]);